shaderText:
struct ShaderUniforms {
  time: f32,
  mouse: vec2<f32>,
}

@group(0)
@binding(0)
var<uniform> shaderUniforms: ShaderUniforms;

@vertex
fn vertexMain(@location(0) pos: vec2f) -> @builtin(position) vec4f {
  return vec4f(pos, 0, 1);
}

@fragment
fn fragmentMain(
  @builtin(position) gl_FragCoord: vec4f,
) -> @location(0) vec4f {
  let position = ( gl_FragCoord.xy / vec2(256, 256) );

  let time = shaderUniforms.time; // E.g. 16.0f;
  let mouse = shaderUniforms.mouse; // E.g. vec2(5.0f, 8.0f);

    var color = 0.0;
    color += sin( position.x * cos( time / 15.0 ) * 80.0 ) + cos( position.y * cos( time / 15.0 ) * 10.0 );
    color += sin( position.y * sin( time / 10.0 ) * 40.0 ) + cos( position.x * sin( time / 25.0 ) * 40.0 );
    color += sin( position.x * sin( time / 5.0 ) * 10.0 ) + sin( position.y * sin( time / 35.0 ) * 80.0 );
    color *= sin( time / 10.0 ) * 0.5;

    return vec4( vec3( color, color * 0.5, cos( color + time / 3.0 ) * 0.75 ), 1.0 );


  //return vec4f(position.x, 0, 0, 1); // (Red, Green, Blue, Alpha)
}
